#include<bits/stdc++.h>
using namespace std;
int a[10100],b[10100],c[10100];
int main(void){
    string A,B;
    cin>>A>>B;
    if(A==B){cout<<'0';return false;}
    else if(A.size()==B.size()&&A<B||A.size()<B.size()){swap(A,B);cout<<'-';}int len=max(A.size(),B.size());
    for(int i=A.size()-1,j=1;i>=0;i--,j++)a[j]=A[i]-'0';
    for(int i=B.size()-1,j=1;i>=0;i--,j++)b[j]=B[i]-'0';
    for(int i=1;i<=len;i++){
        c[i]=c[i]+a[i]-b[i];
        if(c[i]<0)c[i]+=10,c[i+1]-=1;
    }
    int len2;
    for(len2=len;len2>=1;len2--){if(c[len2])break;}
    if(len2==0)len2=1;
    for(int i=len2;i>=1;i--)cout<<c[i];
    return false;
}
